import studentApiService from "../services/studentApiService.js";

const readFunc = async (req, res) => {
    try{
        
    }catch (error) {
        console.log(error);
        return res.status(500).json({
          EM: "error from server", //error message
          EC: "-1", //error code
          DT: "", //data
        });
    }
}


const createFunc = (req, res) => {
    try {
        let data = req.body;
        let dataUser = studentApiService.createNewUser(data);
        return res.status(200).json({
            EM: dataUser.EM,
            EC: dataUser.EC, //error code
            DT: dataUser.DT, //data
        });
    } catch (error) {
      console.log(error);
      return res.status(500).json({
        EM: "error from server", //error message
        EC: "-1", //error code
        DT: "", //data
      });
    }
  };
  
  const updateFunc = (req, res) => {
    try {
    } catch (error) {
      console.log(error);
      return res.status(500).json({
        EM: "error from server", //error message
        EC: "-1", //error code
        DT: "", //data
      });
    }
  };
  
  const deleteFunc = async (req, res) => {
    try {
      let data = await userApiService.deleteUser(req.body.id);
      return res.status(200).json({
          EM: data.EM,
          EC: data.EC, //error code
          DT: data.DT, //data
        });
    } catch (error) {
      console.log(error);
      return res.status(500).json({
        EM: "error from server", //error message
        EC: "-1", //error code
        DT: "", //data
      });
    }
  };

  module.exports = {
    readFunc,
    createFunc,
    updateFunc,
    deleteFunc
  }

